import json
import os
from dataclasses import dataclass, field
from collections import Counter
from pathlib import Path


@dataclass
class TaskObservation:
    participant_id: str
    role: str
    capability_requested: str
    frequency: int  # how many sessions mentioned this
    trust_conditions: list[str] = field(default_factory=list)
    verbatim_quote: str = ""


@dataclass
class EdgeCase:
    description: str
    raised_by_roles: list[str]
    example_input: str
    severity: str  # "blocker" | "high" | "medium" | "low"


@dataclass
class ResearchArtifacts:
    capabilities: list[TaskObservation]
    edge_cases: list[EdgeCase]
    anti_goals: list[str]
    trust_matrix: dict[str, list[str]]  # role -> list of trust conditions


def load_transcript(path: Path) -> dict:
    # Load a coded interview transcript JSON file.
    with open(path) as f:
        return json.load(f)


def synthesize_interviews(transcripts_dir: str) -> ResearchArtifacts:
    # Synthesize coded interview transcripts into structured research artifacts.
    #
    # Each transcript JSON has the shape:
    # {
    #   "participant_id": "P-07",
    #   "role": "clinical_coordinator",
    #   "capability_codes": ["draft_note", "flag_abnormal", "route_to_physician"],
    #   "trust_conditions": ["must show source", "never auto-send"],
    #   "edge_cases": [
    #     {"description": "...", "example_input": "...", "severity": "blocker"}
    #   ],
    #   "anti_goals": ["replace physician judgment", "expose raw model output"]
    # }
    capability_counter: Counter = Counter()
    role_trust: dict[str, set] = {}
    raw_edge_cases: list[dict] = []
    all_anti_goals: list[str] = []
    role_for_participant: dict[str, str] = {}
    trust_conditions_per_cap: dict[str, list] = {}
    quotes: dict[str, str] = {}

    transcript_paths = list(Path(transcripts_dir).glob("*.json"))
    if not transcript_paths:
        raise FileNotFoundError(f"No transcript files found in {transcripts_dir}")

    for path in sorted(transcript_paths):
        t = load_transcript(path)
        pid = t["participant_id"]
        role = t["role"]
        role_for_participant[pid] = role

        for cap in t.get("capability_codes", []):
            capability_counter[cap] += 1
            trust_conditions_per_cap.setdefault(cap, []).extend(t.get("trust_conditions", []))

        role_trust.setdefault(role, set()).update(t.get("trust_conditions", []))

        for ec in t.get("edge_cases", []):
            ec["raised_by_role"] = role
            raw_edge_cases.append(ec)

        all_anti_goals.extend(t.get("anti_goals", []))

        if t.get("key_quote"):
            quotes[pid] = t["key_quote"]

    # Build capability observations (threshold: mentioned by >= 3 participants)
    capabilities = []
    for cap, freq in capability_counter.most_common():
        if freq >= 3:
            capabilities.append(TaskObservation(
                participant_id="aggregate",
                role="multiple",
                capability_requested=cap,
                frequency=freq,
                trust_conditions=list(set(trust_conditions_per_cap.get(cap, []))),
            ))

    # Deduplicate edge cases by description, merging roles
    ec_map: dict[str, EdgeCase] = {}
    for raw in raw_edge_cases:
        key = raw["description"]
        if key not in ec_map:
            ec_map[key] = EdgeCase(
                description=key,
                raised_by_roles=[raw["raised_by_role"]],
                example_input=raw.get("example_input", ""),
                severity=raw.get("severity", "medium"),
            )
        else:
            ec_map[key].raised_by_roles.append(raw["raised_by_role"])

    # Severity sort order
    severity_order = {"blocker": 0, "high": 1, "medium": 2, "low": 3}
    sorted_edge_cases = sorted(ec_map.values(), key=lambda e: severity_order.get(e.severity, 99))

    # Deduplicate anti-goals
    unique_anti_goals = list(dict.fromkeys(all_anti_goals))

    # Trust matrix: role -> unique conditions
    trust_matrix = {role: sorted(conditions) for role, conditions in role_trust.items()}

    return ResearchArtifacts(
        capabilities=capabilities,
        edge_cases=sorted_edge_cases,
        anti_goals=unique_anti_goals,
        trust_matrix=trust_matrix,
    )


def render_scope_brief(artifacts: ResearchArtifacts) -> str:
    lines = ["# Scope Negotiation Brief\n"]
    lines.append("## Prioritised Capabilities (mentioned by ≥ 3 participants)\n")
    for obs in artifacts.capabilities:
        lines.append(f"- **{obs.capability_requested}** ({obs.frequency} participants)")
        if obs.trust_conditions:
            for tc in obs.trust_conditions:
                lines.append(f"  - Trust condition: {tc}")

    lines.append("\n## Edge Cases\n")
    for ec in artifacts.edge_cases:
        roles = ", ".join(set(ec.raised_by_roles))
        lines.append(f"- [{ec.severity.upper()}] {ec.description}")
        lines.append(f"  - Raised by: {roles}")
        if ec.example_input:
            lines.append(f"  - Example: {ec.example_input}")

    lines.append("\n## Anti-Goals\n")
    for ag in artifacts.anti_goals:
        lines.append(f"- {ag}")

    lines.append("\n## Trust Requirements by Role\n")
    for role, conditions in artifacts.trust_matrix.items():
        lines.append(f"### {role}")
        for c in conditions:
            lines.append(f"- {c}")

    return "\n".join(lines)


if __name__ == "__main__":
    import sys
    transcripts_dir = sys.argv[1] if len(sys.argv) > 1 else "transcripts/"
    artifacts = synthesize_interviews(transcripts_dir)
    print(render_scope_brief(artifacts))
